## Critical Issues

### 🔴 1. Unauthenticated `/users` Endpoint Exposing PII
**Lines 11–15 | OWASP A01 + A02**

The `/users` endpoint returns names and email addresses to any anonymous caller. This violates GDPR/CCPA requirements and enables user enumeration.

```js
// ❌ CURRENT — anyone can call GET /users
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});

// ✅ FIX — gate behind authentication middleware
app.get('/users', authenticateToken, authorizeRole('admin'), async (req, res) => {
  // Return only what the caller is authorized to see
  const users = await UserService.findAll({ fields: ['id', 'name'] }); // omit email unless needed
  res.json(users);
});
```

---

### 🔴 2. No Authentication on Any Route
**All lines | OWASP A07**

No JWT, session, or API-key validation exists anywhere. Add a reusable middleware:

```js
const jwt = require('jsonwebtoken');

function authenticateToken(req, res, next) {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer <token>

  if (!token) return res.status(401).json({ error: 'Authentication required' });

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Invalid or expired token' });
    req.user = user;
    next();
  });
}

function authorizeRole(...roles) {
  return (req, res, next) => {
    if (!roles.includes(req.user?.role)) {
      return res.status(403).json({ error: 'Insufficient permissions' });
    }
    next();
  };
}
```

---

## High Issues

### 🟠 3. No HTTPS / TLS Enforcement
**Lines 18–20 | OWASP A02**

The server listens on plain HTTP. Email addresses and tokens travel in cleartext.

```js
// ✅ FIX — use HTTPS in production
const https = require('https');
const fs = require('fs');

if (process.env.NODE_ENV === 'production') {
  const options = {
    key: fs.readFileSync(process.env.TLS_KEY_PATH),
    cert: fs.readFileSync(process.env.TLS_CERT_PATH),
  };
  https.createServer(options, app).listen(443);

  // Redirect HTTP → HTTPS
  const http = require('http');
  http.createServer((req, res) => {
    res.writeHead(301, { Location: `https://${req.headers.host}${req.url}` });
    res.end();
  }).listen(80);
} else {
  app.listen(3000);
}
```

---

### 🟠 4. Missing HTTP Security Headers
**All routes | OWASP A05**

No `X-Frame-Options`, `X-Content-Type-Options`, `HSTS`, `CSP`, or `Referrer-Policy` headers are set. Use **helmet**:

```js
const helmet = require('helmet');

app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      objectSrc: ["'none'"],
    },
  },
  hsts: {
    maxAge: 31536000,       // 1 year
    includeSubDomains: true,
    preload: true,
  },
}));
```

---

### 🟠 5. No Security Logging
**All routes | OWASP A09**

There is zero audit trail. Who accessed `/users`? Were there failed auth attempts? Install **morgan** for access logs and a structured logger for security events:

```js
const morgan = require('morgan');
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.File({ filename: 'security.log' })],
});

// Log every request with IP, method, path, status, and response time
app.use(morgan('combined', {
  stream: { write: (msg) => logger.info(msg.trim()) },
}));

// Log auth failures explicitly
function authenticateToken(req, res, next) {
  // ...
  if (!token) {
    logger.warn({ event: 'auth_missing', ip: req.ip, path: req.path });
    return res.status(401).json({ error: 'Authentication required' });
  }
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) {
      logger.warn({ event: 'auth_invalid', ip: req.ip, path: req.path });
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
}
```

